for slug, text in expansions.items():
    fp = os.path.join(ROLES_DIR, f"{slug}.json")
    with open(fp, 'r', encoding='utf-8') as f:
        data = json.load(f)
    old = len(data['systemPrompt'])
    data['systemPrompt'] += text
    new_len = len(data['systemPrompt'])
    with open(fp, 'w', encoding='utf-8') as f:
        json.dump(data, f, indent=2, ensure_ascii=False)
    # verify
    with open(fp, 'r', encoding='utf-8') as f:
        json.load(f)
    status = 'PASS' if new_len >= 12000 else f'NEEDS MORE ({new_len})'
    print(f"{slug}: {old} -> {new_len} ({status})")

